solution_code:
#include <iostream>

constexpr int gcd(int a, int b) {
    while (b != 0) {
        int t = b;
        b = a % b;
        a = t;
    }
    return a;
}

int main() {
    constexpr int ct = gcd(12, 8);
    std::cout << "Compile-time GCD(12, 8): " << ct << "\n";

    int a, b;
    std::cin >> a >> b;
    std::cout << "Runtime GCD(" << a << ", " << b << "): " << gcd(a, b) << "\n";
    return 0;
}

