solution_code:
#include <iostream>
#include <iomanip>

template <typename T>
constexpr T cabs(T x) {
    return x < T{0} ? -x : x;
}

int main() {
    constexpr int ci = cabs(-5);
    constexpr double cd = cabs(-2.5);
    (void)ci; (void)cd;

    int n;
    std::cin >> n;
    double d;
    std::cin >> d;

    std::cout << "Int abs: " << cabs(n) << "\n";
    std::cout << "Double abs: " << std::fixed << std::setprecision(1) << cabs(d) << "\n";
    return 0;
}
